mapper.select:
SELECT ISNULL(SUM(WORK_MIN), 0)
FROM HRTDAILYATTENDANCE01
WHERE COMPANY  = #{company}
  AND EMP_CODE = #{empCode}
  AND YYYYMMDD BETWEEN #{weekStart} AND #{weekEnd}
  AND YYYYMMDD != #{excludeYmd}

mapper.delete:
DELETE FROM HRTDAILYATTENDANCE01
WHERE COMPANY  = #{company}
  AND EMP_CODE = #{empCode}
  AND YYYYMMDD = #{yyyymmdd}
